INSERT INTO public.exercises (external_id,name,muscle_group,secondary_muscles,equipment,category,instructions,description,image_url,source,is_public) VALUES ('Rocket_Jump','Rocket Jump','cuádriceps',ARRAY['pantorrillas','isquiotibiales'],'peso corporal','plyometrics',ARRAY['Begin in a relaxed stance with your feet shoulder width apart and hold your arms close to the body.','To initiate the move, squat down halfway and explode back up as high as possible.','Fully extend your entire body, reaching overhead as far as possible. As you land, absorb your impact through the legs.'],'Begin in a relaxed stance with your feet shoulder width apart and hold your arms close to the body. To initiate the move, squat down halfway and explode back up as high as possible. Fully extend your entire body, reaching overhead as far as possible. As you land, absorb your impact through the legs.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Rocket_Jump/0.jpg','exercisedb',true),('Rocking_Standing_Calf_Raise','Rocking Standing Calf Raise','pantorrillas',ARRAY[]::text[],'barra','strength',ARRAY['This exercise is best performed inside a squat rack for safety purposes. To begin, first set the bar on a rack that best matches your height. Once the correct height is chosen and the bar is loaded, step under the bar and place it on the back of your shoulders (slightly below the neck).','Hold on to the bar using both arms at each side and lift it off the rack by first pushing with your legs and at the same time straightening your torso.','Step away from the rack and position your legs using a shoulder width medium stance with the toes slightly pointed out. Keep your head up at all times as looking down will get you off balance. Also maintain a straight back and keep the knees with a slight bend; never locked. This will be your starting position.','Raise your heels as you breathe out by extending your ankles as high as possible and flexing your calf. Ensure that the knee is kept stationary at all times. There should be no bending (other than the slight initial bend we created during positioning) at any time. Hold the contracted position by a second before you start to go back down.','Go back slowly to the starting position as you breathe in by lowering your heels as you bend the ankles until calves are stretched.','Now lift your toes by contracting the tibia muscles in the front of the calves as you breathe out.','Hold for a second and bring them back down as you breathe in.','Repeat for the recommended amount of repetitions.'],'This exercise is best performed inside a squat rack for safety purposes. To begin, first set the bar on a rack that best matches your height. Once the correct height is chosen and the bar is loaded, step under the bar and place it on the back of your shoulders (slightly below the neck). Hold on to the bar using both arms at each side and lift it off the rack by first pushing with your legs and at the same time straightening your torso. Step away from the rack and position your legs using a shoulder width medium stance with the toes slightly pointed out. Keep your head up at all times as looking down will get you off balance. Also maintain a straight back and keep the knees with a slight bend; never locked. This will be your starting position. Raise your heels as you breathe out by extending your ankles as high as possible and flexing your calf. Ensure that the knee is kept stationary at all times. There should be no bending (other than the slight initial bend we created during positioning) at any time. Hold the contracted position by a second before you start to go back down. Go back slowly to the starting position as you breathe in by lowering your heels as you bend the ankles until calves are stretched. Now lift your toes by contracting the tibia muscles in the front of the calves as you breathe out. Hold for a second and bring them back down as you breathe in. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Rocking_Standing_Calf_Raise/0.jpg','exercisedb',true),('Rocky_Pull-Ups_Pulldowns','Rocky Pull-Ups/Pulldowns','dorsales',ARRAY['bíceps','espalda media','hombros'],'otro','strength',ARRAY['Grab the pull-up bar with the palms facing forward using a wide grip.','As you have both arms extended in front of you holding the bar at the chosen grip width, bring your torso back around 30 degrees or so while creating a curvature on your lower back and sticking your chest out. This is your starting position.','Pull your torso up until the bar touches your upper chest by drawing the shoulders and the upper arms down and back. Exhale as you perform this portion of the movement. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. The upper torso should remain stationary as it moves through space and only the arms should move. The forearms should do no other work other than hold the bar.','After a second on the contracted position, start to inhale and slowly lower your torso back to the starting position when your arms are fully extended and the lats are fully stretched.','Now repeat the same movements as described above except this time your torso will remain straight as you go up and the bar will touch the back of the neck instead of the upper chest. Tip: Use the head to lean forward slightly as it will help you properly execute this portion of the exercise.','Once you have lowered yourself back down to the starting position, repeat the exercise for the prescribed amount of repetitions in your program.'],'Grab the pull-up bar with the palms facing forward using a wide grip. As you have both arms extended in front of you holding the bar at the chosen grip width, bring your torso back around 30 degrees or so while creating a curvature on your lower back and sticking your chest out. This is your starting position. Pull your torso up until the bar touches your upper chest by drawing the shoulders and the upper arms down and back. Exhale as you perform this portion of the movement. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. The upper torso should remain stationary as it moves through space and only the arms should move. The forearms should do no other work other than hold the bar. After a second on the contracted position, start to inhale and slowly lower your torso back to the starting position when your arms are fully extended and the lats are fully stretched. Now repeat the same movements as described above except this time your torso will remain straight as you go up and the bar will touch the back of the neck instead of the upper chest. Tip: Use the head to lean forward slightly as it will help you properly execute this portion of the exercise. Once you have lowered yourself back down to the starting position, repeat the exercise for the prescribed amount of repetitions in your program.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Rocky_Pull-Ups_Pulldowns/0.jpg','exercisedb',true),('Romanian_Deadlift','Romanian Deadlift','isquiotibiales',ARRAY['pantorrillas','glúteos','espalda baja'],'barra','strength',ARRAY['Put a barbell in front of you on the ground and grab it using a pronated (palms facing down) grip that a little wider than shoulder width. Tip: Depending on the weight used, you may need wrist wraps to perform the exercise and also a raised platform in order to allow for better range of motion.','Bend the knees slightly and keep the shins vertical, hips back and back straight. This will be your starting position.','Keeping your back and arms completely straight at all times, use your hips to lift the bar as you exhale. Tip: The movement should not be fast but steady and under control.','Once you are standing completely straight up, lower the bar by pushing the hips back, only slightly bending the knees, unlike when squatting. Tip: Take a deep breath at the start of the movement and keep your chest up. Hold your breath as you lower and exhale as you complete the movement.','Repeat for the recommended amount of repetitions.'],'Put a barbell in front of you on the ground and grab it using a pronated (palms facing down) grip that a little wider than shoulder width. Tip: Depending on the weight used, you may need wrist wraps to perform the exercise and also a raised platform in order to allow for better range of motion. Bend the knees slightly and keep the shins vertical, hips back and back straight. This will be your starting position. Keeping your back and arms completely straight at all times, use your hips to lift the bar as you exhale. Tip: The movement should not be fast but steady and under control. Once you are standing completely straight up, lower the bar by pushing the hips back, only slightly bending the knees, unlike when squatting. Tip: Take a deep breath at the start of the movement and keep your chest up. Hold your breath as you lower and exhale as you complete the movement. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Romanian_Deadlift/0.jpg','exercisedb',true),('Romanian_Deadlift_from_Deficit','Romanian Deadlift from Deficit','isquiotibiales',ARRAY['antebrazos','glúteos','espalda baja','trapecios'],'barra','olympic weightlifting',ARRAY['Begin standing while holding a bar at arm''''s length in front of you. You can stand on a raised platform to increase the range of motion.','Begin by flexing the knees slightly, and then flex at the hip, moving your butt back as far as possible, lowering the torso as far as flexibility allows. The back should remain in absolute extension at all times, and the bar should remain in contact with the legs. If done properly, there should be heavy tension felt in the hamstrings.','Reverse the motion to return to the starting position.'],'Begin standing while holding a bar at arm''s length in front of you. You can stand on a raised platform to increase the range of motion. Begin by flexing the knees slightly, and then flex at the hip, moving your butt back as far as possible, lowering the torso as far as flexibility allows. The back should remain in absolute extension at all times, and the bar should remain in contact with the legs. If done properly, there should be heavy tension felt in the hamstrings. Reverse the motion to return to the starting position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Romanian_Deadlift_from_Deficit/0.jpg','exercisedb',true),('Rope_Climb','Rope Climb','dorsales',ARRAY['bíceps','antebrazos','espalda media','hombros'],'otro','strength',ARRAY['Grab the rope with both hands above your head. Pull down on the rope as you take a small jump.','Wrap the rope around one leg, using your feet to pinch the rope. Reach up as high as possible with your arms, gripping the rope tightly.','Release the rope from your feet as you pull yourself up with your arms, bringing your knees towards your chest.','Resecure your feet on the rope, and then stand up to take another high hold on the rope. Continue until you reach the top of the rope.','To lower yourself, loosen the grip of your feet on the rope as you slide down using a hand over hand motion.'],'Grab the rope with both hands above your head. Pull down on the rope as you take a small jump. Wrap the rope around one leg, using your feet to pinch the rope. Reach up as high as possible with your arms, gripping the rope tightly. Release the rope from your feet as you pull yourself up with your arms, bringing your knees towards your chest. Resecure your feet on the rope, and then stand up to take another high hold on the rope. Continue until you reach the top of the rope. To lower yourself, loosen the grip of your feet on the rope as you slide down using a hand over hand motion.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Rope_Climb/0.jpg','exercisedb',true),('Rope_Crunch','Rope Crunch','abdominales',ARRAY[]::text[],'cable','strength',ARRAY['Kneel 1-2 feet in front of a cable system with a rope attached.','After selecting an appropriate weight, grasp the rope with both hands reaching overhead. Your torso should be upright in the starting position.','To begin, flex at the spine, attempting to bring your rib cage to your legs as you pull the cable down.','Pause at the bottom of the motion, and then slowly return to the starting position.','These can be done with twists or to the side to hit the obliques.'],'Kneel 1-2 feet in front of a cable system with a rope attached. After selecting an appropriate weight, grasp the rope with both hands reaching overhead. Your torso should be upright in the starting position. To begin, flex at the spine, attempting to bring your rib cage to your legs as you pull the cable down. Pause at the bottom of the motion, and then slowly return to the starting position. These can be done with twists or to the side to hit the obliques.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Rope_Crunch/0.jpg','exercisedb',true),('Rope_Jumping','Rope Jumping','cuádriceps',ARRAY['pantorrillas','isquiotibiales'],'otro','cardio',ARRAY['Hold an end of the rope in each hand. Position the rope behind you on the ground. Raise your arms up and turn the rope over your head bringing it down in front of you. When it reaches the ground, jump over it. Find a good turning pace that can be maintained. Different speeds and techniques can be used to introduce variation.','Rope jumping is exciting, challenges your coordination, and requires a lot of energy. A 150 lb person will burn about 350 calories jumping rope for 30 minutes, compared to over 450 calories running.'],'Hold an end of the rope in each hand. Position the rope behind you on the ground. Raise your arms up and turn the rope over your head bringing it down in front of you. When it reaches the ground, jump over it. Find a good turning pace that can be maintained. Different speeds and techniques can be used to introduce variation. Rope jumping is exciting, challenges your coordination, and requires a lot of energy. A 150 lb person will burn about 350 calories jumping rope for 30 minutes, compared to over 450 calories running.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Rope_Jumping/0.jpg','exercisedb',true),('Rope_Straight-Arm_Pulldown','Rope Straight-Arm Pulldown','dorsales',ARRAY[]::text[],'cable','strength',ARRAY['Attach a rope to a high pulley and make your weight selection. Stand a couple feet back from the pulley with your feet staggered and take the rope with both hands. Lean forward from the hip, keeping your back straight, with your arms extended up in front of you. This will be your starting position.','Keeping your arms straight, extend the shoulder to pull the rope down to your thighs.','Pause at the bottom of the motion, squeezing your lats.','Return to the starting position without allowing the weight to fully rest on the stack.'],'Attach a rope to a high pulley and make your weight selection. Stand a couple feet back from the pulley with your feet staggered and take the rope with both hands. Lean forward from the hip, keeping your back straight, with your arms extended up in front of you. This will be your starting position. Keeping your arms straight, extend the shoulder to pull the rope down to your thighs. Pause at the bottom of the motion, squeezing your lats. Return to the starting position without allowing the weight to fully rest on the stack.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Rope_Straight-Arm_Pulldown/0.jpg','exercisedb',true),('Round_The_World_Shoulder_Stretch','Round The World Shoulder Stretch','hombros',ARRAY['bíceps','pecho'],'otro','stretching',ARRAY['Stand up straight with your legs together, holding a bodybar or broomstick.','Hold the pole behind your hips with a wider than shoulder width grip. Your palms should be down and your thumbs facing out.','Slowly lift your arms up behind your head. Don''''t force it if it gets hard to lift further.'],'Stand up straight with your legs together, holding a bodybar or broomstick. Hold the pole behind your hips with a wider than shoulder width grip. Your palms should be down and your thumbs facing out. Slowly lift your arms up behind your head. Don''t force it if it gets hard to lift further.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Round_The_World_Shoulder_Stretch/0.jpg','exercisedb',true);